const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const projectId = response?.data?.id;
if (!projectId) throw new Error('WayinVideo did not return a project ID. Check API key and video URL.');

return [{
  json: {
    projectId,
    status: response.data.status || 'CREATED',
    videoTitle: config.videoTitle,
    videoUrl: config.videoUrl,
    submittedBy: config.submittedBy,
    submittedAt: config.submittedAt,
    maxClips: config.maxClips,
    wayinVideoApiKey: config.wayinVideoApiKey,
    exportRatio: config.exportRatio,
    exportResolution: config.exportResolution,
    sheetId: config.sheetId,
    sheetName: config.sheetName,
    recipientEmail: config.recipientEmail,
    senderName: config.senderName,
    pollCount: 0
  }
}];

const pollResponse = $input.first().json;
const prev = $('4. Code — Save Clipping Project ID').item.json;

const status = pollResponse?.data?.status || 'UNKNOWN';
const pollCount = (prev.pollCount || 0) + 1;

if (pollCount >= 25 && status !== 'SUCCEEDED') {
  throw new Error('WayinVideo clipping timeout after 25 polls (~25 min). Project: ' + prev.projectId);
}

if (status === 'FAILED') {
  const errMsg = pollResponse?.data?.error_message || 'Unknown error';
  throw new Error('WayinVideo clipping failed: ' + errMsg);
}

return [{
  json: {
    projectId: prev.projectId,
    status,
    clips: pollResponse?.data?.clips || [],
    pollCount,
    isReady: status === 'SUCCEEDED',
    videoTitle: prev.videoTitle,
    videoUrl: prev.videoUrl,
    submittedBy: prev.submittedBy,
    submittedAt: prev.submittedAt,
    maxClips: prev.maxClips,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    exportRatio: prev.exportRatio,
    exportResolution: prev.exportResolution,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    recipientEmail: prev.recipientEmail,
    senderName: prev.senderName
  }
}];

const data = $input.first().json;
const allClips = data.clips || [];

if (allClips.length === 0) {
  throw new Error('WayinVideo returned no clips for this video.');
}

const topClips = [...allClips]
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, data.maxClips || 3);

const clipIndices = topClips.map(c => c.idx);

return [{
  json: {
    projectId: data.projectId,
    clipIndices,
    topClips,
    totalFound: allClips.length,
    exporting: topClips.length,
    videoTitle: data.videoTitle,
    submittedBy: data.submittedBy,
    submittedAt: data.submittedAt,
    wayinVideoApiKey: data.wayinVideoApiKey,
    exportRatio: data.exportRatio,
    exportResolution: data.exportResolution,
    sheetId: data.sheetId,
    sheetName: data.sheetName,
    recipientEmail: data.recipientEmail,
    senderName: data.senderName
  }
}];

const response = $input.first().json;
const prev = $('10. Code — Select Top Clips for Export').item.json;

const exportTaskId = response?.data?.export_task_id;
if (!exportTaskId) throw new Error('WayinVideo export did not return export_task_id.');

return [{
  json: {
    exportTaskId,
    exportStatus: response.data.status || 'CREATED',
    topClips: prev.topClips,
    totalFound: prev.totalFound,
    exporting: prev.exporting,
    videoTitle: prev.videoTitle,
    submittedBy: prev.submittedBy,
    submittedAt: prev.submittedAt,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    exportRatio: prev.exportRatio,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    recipientEmail: prev.recipientEmail,
    senderName: prev.senderName,
    exportPollCount: 0
  }
}];

const pollResponse = $input.first().json;
const prev = $('12. Code — Save Export Task ID').item.json;

const status = pollResponse?.data?.status || 'UNKNOWN';
const exportPollCount = (prev.exportPollCount || 0) + 1;

if (exportPollCount >= 20 && status !== 'SUCCEEDED') {
  throw new Error('WayinVideo export timeout after 20 polls (~20 min). Export: ' + prev.exportTaskId);
}

if (status === 'FAILED') {
  throw new Error('WayinVideo export failed: ' + (pollResponse?.data?.error_message || 'Unknown error'));
}

return [{
  json: {
    exportTaskId: prev.exportTaskId,
    exportStatus: status,
    exportedClips: pollResponse?.data?.clips || [],
    exportPollCount,
    isExportReady: status === 'SUCCEEDED',
    topClips: prev.topClips,
    totalFound: prev.totalFound,
    videoTitle: prev.videoTitle,
    submittedBy: prev.submittedBy,
    submittedAt: prev.submittedAt,
    wayinVideoApiKey: prev.wayinVideoApiKey,
    sheetId: prev.sheetId,
    sheetName: prev.sheetName,
    recipientEmail: prev.recipientEmail,
    senderName: prev.senderName
  }
}];

const data = $input.first().json;
const exportedClips = data.exportedClips || [];
const topClips = data.topClips || [];

const clipsWithLinks = topClips.map(tc => {
  const exported = exportedClips.find(ec => ec.idx === tc.idx);
  return {
    ...tc,
    exportLink: exported?.export_link || 'Processing'
  };
});

const msToTime = ms => {
  const s = Math.floor((ms || 0) / 1000);
  return Math.floor(s / 60) + ':' + String(s % 60).padStart(2, '0');
};

const loggedAt = new Date().toISOString().replace('T', ' ').substring(0, 16);
const today = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

const sheetRows = clipsWithLinks.map((clip, i) => ({
  date: today,
  videoTitle: data.videoTitle,
  clipNum: i + 1,
  clipTitle: clip.title || 'Clip ' + (i + 1),
  durationSec: Math.round(((clip.end_ms || 0) - (clip.begin_ms || 0)) / 1000),
  viralScore: clip.score || 0,
  tags: (clip.tags || []).join(', '),
  description: (clip.desc || '').substring(0, 200),
  exportLink: clip.exportLink,
  loggedAt,
  sheetId: data.sheetId,
  sheetName: data.sheetName,
  isLastRow: i === clipsWithLinks.length - 1,
  clipsWithLinks: i === clipsWithLinks.length - 1 ? clipsWithLinks : [],
  totalFound: data.totalFound,
  submittedBy: data.submittedBy,
  submittedAt: data.submittedAt,
  recipientEmail: data.recipientEmail,
  senderName: data.senderName
}));

return sheetRows.map(r => ({ json: r }));

const data = $json;
const clips = data.clipsWithLinks || [];

let clipLines = '';
clips.forEach((clip, i) => {
  const dur = Math.round(((clip.end_ms || 0) - (clip.begin_ms || 0)) / 1000);
  const tags = (clip.tags || []).join(', ');
  clipLines +=
    '\n--- Clip ' + (i + 1) + ' ---\n' +
    'Title: ' + (clip.title || 'Untitled') + '\n' +
    'Duration: ' + dur + ' seconds | Viral Score: ' + (clip.score || 0) + '/100\n' +
    'Tags: ' + tags + '\n' +
    'Description: ' + (clip.desc || '').substring(0, 150) + '\n' +
    'Download Link: ' + (clip.exportLink || 'Not available') + '\n';
});

const emailSubject = 'Social Media Clips Ready — ' + data.videoTitle;

const emailBody =
  'Hi ' + data.submittedBy + ',\n\n' +
  'Your social media clips are ready! Here are the top ' + clips.length + ' clips from your webinar.\n\n' +
  'VIDEO: ' + data.videoTitle + '\n' +
  'Total clips found: ' + data.totalFound + ' | Exported: ' + clips.length + '\n' +
  'Format: 9:16 vertical | Captions: Yes | AI Hook: Yes\n' +
  'Submitted: ' + data.submittedAt + '\n' +
  clipLines +
  '\nIMPORTANT: Download links expire in 24 hours. Download now!\n\n' +
  'All clips also logged in Google Sheets for reference.\n\n' +
  'Best regards,\n' +
  data.senderName;

return [{
  json: {
    emailSubject,
    emailBody,
    recipientEmail: data.recipientEmail
  }
}];
